import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

function cloneGrid(grid) {
	return grid.map(row => row.slice());
}

function createEmptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

function createGrid() {
	const grid = writable(createEmptyGrid());
	const userGrid = writable(createEmptyGrid());
	const canUndo = writable(false);
	const canRedo = writable(false);
	let currentGame = createGame({ sudoku: createSudoku(createEmptyGrid()) });

	function syncFromGame() {
		// UI 仍然通过 Svelte store 渲染，但真正的状态来源是领域层的 Game 对象。
		userGrid.set(currentGame.getSudoku().getGrid());
		canUndo.set(currentGame.canUndo());
		canRedo.set(currentGame.canRedo());
	}

	function resetGame(nextGrid) {
		// 新开一局时直接替换整个会话对象，历史记录也会随之自然清空。
		const snapshot = cloneGrid(nextGrid);
		grid.set(snapshot);
		currentGame = createGame({ sudoku: createSudoku(snapshot) });
		syncFromGame();
	}

	return {
		subscribe: grid.subscribe,
		userGridSubscribe: userGrid.subscribe,
		canUndoSubscribe: canUndo.subscribe,
		canRedoSubscribe: canRedo.subscribe,

		generate(difficulty) {
			resetGame(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			resetGame(decodeSencode(sencode));
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},

		set(pos, value) {
			currentGame.guess({ row: pos.y, col: pos.x, value });
			syncFromGame();
		},

		applyHint(pos) {
			hints.useHint();
			const solvedSudoku = solveSudoku(get(userGrid));
			// 提示也走同一套 game API，这样它和普通输入一样可被撤销/重做。
			currentGame.guess({
				row: pos.y,
				col: pos.x,
				value: solvedSudoku[pos.y][pos.x],
			});
			syncFromGame();
		},

		undo() {
			currentGame.undo();
			syncFromGame();
		},

		redo() {
			currentGame.redo();
			syncFromGame();
		},
	};
}

export const grid = createGrid();
export const userGrid = {
	subscribe: grid.userGridSubscribe,
	set: (pos, value) => grid.set(pos, value),
	applyHint: pos => grid.applyHint(pos),
};
export const canUndo = {
	subscribe: grid.canUndoSubscribe,
};
export const canRedo = {
	subscribe: grid.canRedoSubscribe,
};

export const invalidCells = derived(userGrid, $userGrid => {
	const _invalidCells = [];

	const addInvalid = (x, y) => {
		const xy = x + ',' + y;
		if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
	};

	for (let y = 0; y < SUDOKU_SIZE; y++) {
		for (let x = 0; x < SUDOKU_SIZE; x++) {

			const value = $userGrid[y][x];

			if (value) {
				for (let i = 0; i < SUDOKU_SIZE; i++) {
					// 检查当前行是否出现重复数字
					if (i !== x && $userGrid[y][i] === value) {
						addInvalid(x, y);
					}

					// 检查当前列是否出现重复数字
					if (i !== y && $userGrid[i][x] === value) {
						addInvalid(x, i);
					}
				}

				// 检查当前 3x3 宫内是否出现重复数字
				const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
				const endY = startY + BOX_SIZE;
				const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
				const endX = startX + BOX_SIZE;
				for (let row = startY; row < endY; row++) {
					for (let col = startX; col < endX; col++) {
						if (row !== y && col !== x && $userGrid[row][col] === value) {
							addInvalid(col, row);
						}
					}
				}
			}

		}
	}

	return _invalidCells;
}, []);
